  ('public-health-specialist-moex-00986', 'public-health-specialist', 'public-health-specialist-moex-110-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '臨床心理師將 18 位病情相當的輕度失智症患者完全隨機分派到下表三種治療方式，每一種 治療方式有6人，持續進行3個月的治療，之後接受憂鬱量表的測量。治療後的憂鬱量表測 量分數描述統計量如下，分數越高表示憂鬱傾向越高。臨床心理師執行變異數分析，請問此 變異數分析表中之組間變異平方和（SumofSquaresBetweenGroups）大約為何？ 個數 平均數 標準差 標準誤 有氧運動 6 8.00 1.414 .577 音樂療法 6 12.00 3.347 1.366 認知療法 6 25.00 2.828 1.155 總和 18 15.00 7.874 1.856', '["1422", "948", "474", "106"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:41+00:00", "source_pdf_sha1": "8cc212619220", "answer_pdf_sha1": "4c6140f93ee8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
